#include<bits/stdc++.h>
using namespace std;
int main(){
    long long n,b,h[200009];
    long long ans=0;
    cin>>n>>b;
    for(int i=0;i<n;i++){
        cin>>h[i];
    }
    sort(h,h+n);
    for(int i=n;i>0;i--){
        ans+=h[i];
        if(ans>b) {cout<<n-i;break;}
    }
    return 0;
}
